import javax.xml.XMLConstants;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.parsers.ParserConfigurationException;
import java.io.File;
import java.io.IOException;

/**
 * XML Configuration Parsing Service
 * 
 * This service provides secure XML parsing capabilities for enterprise applications.
 * It uses JAXP's DocumentBuilderFactory with security features enabled to prevent
 * XML External Entity (XXE) attacks and other XML-based vulnerabilities.
 * 
 * @author Enterprise Development Team
 * @version 1.0
 * @since Java 8
 */
public class ConfigService {

    /**
     * Loads and parses an XML configuration file from the specified path.
     * 
     * This method implements secure XML parsing by:
     * - Disabling DTD processing to prevent XXE attacks
     * - Disabling external entity resolution
     * - Disabling XInclude processing
     * - Enabling secure processing features
     * 
     * @param configPath the file system path to the XML configuration file
     * @return a parsed Document object representing the XML structure
     * @throws Exception if the XML is malformed, the file cannot be read, 
     *                   or the input is invalid
     * @throws IllegalArgumentException if configPath is null or empty
     */
    public Document loadConfig(String configPath) throws Exception {
        // Validate input parameters
        if (configPath == null || configPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Configuration path cannot be null or empty");
        }

        // Validate file exists and is readable
        File configFile = new File(configPath);
        if (!configFile.exists()) {
            throw new IOException("Configuration file does not exist: " + configPath);
        }
        if (!configFile.isFile()) {
            throw new IOException("Configuration path is not a file: " + configPath);
        }
        if (!configFile.canRead()) {
            throw new IOException("Configuration file is not readable: " + configPath);
        }

        DocumentBuilderFactory factory = null;
        DocumentBuilder builder = null;
        Document document = null;

        try {
            // Create DocumentBuilderFactory instance
            factory = DocumentBuilderFactory.newInstance();

            // Security Configuration: Prevent XXE (XML External Entity) attacks
            // Disable DTDs (Document Type Definitions) completely
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);

            // Disable external general entities
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);

            // Disable external parameter entities
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);

            // Disable external DTDs
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

            // Disable XInclude processing
            factory.setXIncludeAware(false);

            // Disable namespace processing if not needed (can be enabled if required)
            factory.setNamespaceAware(false);

            // Enable secure processing
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

            // Additional security: Set access restrictions
            try {
                factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
                factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
            } catch (IllegalArgumentException e) {
                // Some older XML parsers may not support these attributes
                // Log warning in production environment
                System.err.println("Warning: Could not set access restrictions. Parser may not support these features.");
            }

            // Create DocumentBuilder
            builder = factory.newDocumentBuilder();

            // Set error handler for better error reporting
            builder.setErrorHandler(new org.xml.sax.ErrorHandler() {
                @Override
                public void warning(org.xml.sax.SAXParseException exception) throws SAXException {
                    System.err.println("Warning: " + exception.getMessage());
                }

                @Override
                public void error(org.xml.sax.SAXParseException exception) throws SAXException {
                    throw exception;
                }

                @Override
                public void fatalError(org.xml.sax.SAXParseException exception) throws SAXException {
                    throw exception;
                }
            });

            // Parse the XML file
            document = builder.parse(configFile);

            // Normalize the document structure
            document.getDocumentElement().normalize();

            return document;

        } catch (ParserConfigurationException e) {
            throw new Exception("XML parser configuration error: " + e.getMessage(), e);
        } catch (SAXException e) {
            throw new Exception("XML parsing error - invalid XML format: " + e.getMessage(), e);
        } catch (IOException e) {
            throw new Exception("Error reading configuration file: " + e.getMessage(), e);
        } catch (Exception e) {
            throw new Exception("Unexpected error while loading configuration: " + e.getMessage(), e);
        }
    }

    /**
     * Validates if the given path points to a valid XML file.
     * 
     * @param configPath the file path to validate
     * @return true if the path is valid and points to an accessible file
     */
    public boolean isValidConfigPath(String configPath) {
        if (configPath == null || configPath.trim().isEmpty()) {
            return false;
        }

        File configFile = new File(configPath);
        return configFile.exists() && configFile.isFile() && configFile.canRead();
    }
}
